    int clumsy(int n) {
        int res = 1;
        int op = 1;
        for (int i = n; i > 1; --i) {
            if (op == 1) {
                res *= i;
            } else if (op == 2) {
                res /= i;
            } else if (op == 3) {
                res += i;
            } else {
                res -= i;
            }
            op = (op + 1) % 4;
        }
        return res;
    }
};```
